module custom_logic (
    input u,
    input v,
    input w,
    input x,
    output reg obf_trigger);

    always @(*) begin
        case ({u, v, w, x})
            4'b1110: obf_trigger = 1;
            4'b0101: obf_trigger = 0;
            4'b1010: obf_trigger = 1;
            4'b0001: obf_trigger = 1;
            4'b1101: obf_trigger = 0;
            4'b0011: obf_trigger = 1;
            4'b1011: obf_trigger = 0;
            4'b0100: obf_trigger = 1;
            4'b1111: obf_trigger = 0;
            4'b0010: obf_trigger = 0;
            default: obf_trigger = 0;
        endcase
    end
endmodule
